insert into cloud_todo_items
( item_id, list_id, title
, description, item_status, sort_order
, create_time, update_time, completed_time)
values ( #{itemId,jdbcType=VARCHAR}, #{listId,jdbcType=VARCHAR}, #{title,jdbcType=VARCHAR}
       , #{description,jdbcType=VARCHAR}, #{itemStatus,jdbcType=CHAR}, #{sortOrder,jdbcType=INTEGER}
       , #{createTime,jdbcType=TIMESTAMP}, #{updateTime,jdbcType=TIMESTAMP}
       , #{completedTime,jdbcType=TIMESTAMP})

mapper.select:
select
from cloud_todo_items
and list_id = #{query.listId,jdbcType=VARCHAR}
and item_status = #{query.itemStatus,jdbcType=CHAR}
order by item_status asc, case when item_status = 'IS00' then sort_order else null end asc, case when item_status != 'IS00' then update_time else null end desc

select list_id, count(*) as totalCount, sum(case when item_status = 'IS01' then 1 else 0 end) as todoCount, sum(case when item_status = 'IS01' then 1 else 0 end) as completedCount from cloud_todo_items where list_id in
#{listId}
group by list_id
